create type public.app_role as enum ('customer','admin');
create type public.order_status as enum ('new','in_conversation','confirmed','delivered','cancelled');
create table public.profiles(id uuid primary key references auth.users(id) on delete cascade, email text unique, full_name text, whatsapp text, role public.app_role not null default 'customer', created_at timestamptz not null default now());
create table public.calendar_months(id uuid primary key default gen_random_uuid(), title text not null, image_path text, published boolean not null default false, created_at timestamptz not null default now());
create table public.training_events(id uuid primary key default gen_random_uuid(), title text not null, starts_at timestamptz not null, location text not null, maps_url text, description text, published boolean not null default false, created_at timestamptz not null default now());
create table public.products(id uuid primary key default gen_random_uuid(), name text not null, description text, image_path text, price_cents integer not null check(price_cents>=0), active boolean not null default true, created_at timestamptz not null default now());
create table public.product_variants(id uuid primary key default gen_random_uuid(), product_id uuid not null references public.products(id) on delete cascade, label text not null, active boolean not null default true, unique(product_id,label));
create table public.gallery_items(id uuid primary key default gen_random_uuid(), image_path text not null, alt_text text not null, caption text, position integer not null default 0, published boolean not null default false, created_at timestamptz not null default now());
create table public.site_settings(id boolean primary key default true check(id), instagram_url text, email text, whatsapp_number text, content jsonb not null default '{}'::jsonb, updated_at timestamptz not null default now());
create table public.orders(id uuid primary key default gen_random_uuid(), user_id uuid not null references auth.users(id), customer_name text not null, whatsapp text not null, fulfillment_method text not null, status public.order_status not null default 'new', total_cents integer not null check(total_cents>=0), created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.order_items(id uuid primary key default gen_random_uuid(), order_id uuid not null references public.orders(id) on delete cascade, product_name text not null, variant_label text, unit_price_cents integer not null, quantity integer not null check(quantity>0), subtotal_cents integer not null);
create or replace function public.handle_new_user() returns trigger language plpgsql security definer set search_path=public as $$ begin insert into public.profiles(id,email,full_name) values(new.id,new.email,coalesce(new.raw_user_meta_data->>'full_name',new.raw_user_meta_data->>'name')); return new; end; $$;
create trigger on_auth_user_created after insert on auth.users for each row execute procedure public.handle_new_user();
create or replace function public.is_admin() returns boolean language sql stable security definer set search_path=public as $$ select exists(select 1 from public.profiles where id=auth.uid() and role='admin'); $$;
revoke all on function public.is_admin() from public; grant execute on function public.is_admin() to authenticated;
alter table public.profiles enable row level security; alter table public.calendar_months enable row level security; alter table public.training_events enable row level security; alter table public.products enable row level security; alter table public.product_variants enable row level security; alter table public.gallery_items enable row level security; alter table public.site_settings enable row level security; alter table public.orders enable row level security; alter table public.order_items enable row level security;
create policy "profiles own" on public.profiles for select to authenticated using((select auth.uid())=id or (select public.is_admin())); create policy "profiles update own" on public.profiles for update to authenticated using((select auth.uid())=id or (select public.is_admin())) with check((select auth.uid())=id or (select public.is_admin()));
create policy "public calendar" on public.calendar_months for select to anon,authenticated using(published or (select public.is_admin())); create policy "public training" on public.training_events for select to anon,authenticated using(published or (select public.is_admin())); create policy "public products" on public.products for select to anon,authenticated using(active or (select public.is_admin())); create policy "public variants" on public.product_variants for select to anon,authenticated using(active or (select public.is_admin())); create policy "public gallery" on public.gallery_items for select to anon,authenticated using(published or (select public.is_admin())); create policy "public settings" on public.site_settings for select to anon,authenticated using(true);
create policy "admin calendar" on public.calendar_months for all to authenticated using((select public.is_admin())) with check((select public.is_admin())); create policy "admin training" on public.training_events for all to authenticated using((select public.is_admin())) with check((select public.is_admin())); create policy "admin products" on public.products for all to authenticated using((select public.is_admin())) with check((select public.is_admin())); create policy "admin variants" on public.product_variants for all to authenticated using((select public.is_admin())) with check((select public.is_admin())); create policy "admin gallery" on public.gallery_items for all to authenticated using((select public.is_admin())) with check((select public.is_admin())); create policy "admin settings" on public.site_settings for all to authenticated using((select public.is_admin())) with check((select public.is_admin()));
create policy "orders own" on public.orders for select to authenticated using(user_id=(select auth.uid()) or (select public.is_admin())); create policy "orders create own" on public.orders for insert to authenticated with check(user_id=(select auth.uid())); create policy "order items create own" on public.order_items for insert to authenticated with check(exists(select 1 from public.orders o where o.id=order_id and o.user_id=(select auth.uid()))); create policy "orders admin update" on public.orders for update to authenticated using((select public.is_admin())) with check((select public.is_admin())); create policy "order items own" on public.order_items for select to authenticated using(exists(select 1 from public.orders o where o.id=order_id and (o.user_id=(select auth.uid()) or (select public.is_admin()))));
insert into storage.buckets(id,name,public) values('public-media','public-media',true) on conflict(id) do nothing;
create policy "public media read" on storage.objects for select to anon,authenticated using(bucket_id='public-media'); create policy "admin media write" on storage.objects for all to authenticated using(bucket_id='public-media' and (select public.is_admin())) with check(bucket_id='public-media' and (select public.is_admin()));
